import { useEffect } from "react";
import { HashRouter as Router, Routes, Route, Link } from "react-router-dom";
import { useTranslation } from "react-i18next";

import AdminPage from "./pages/AdminPage";
import HomePage from "./pages/HomePage";
import PCBuilderPage from "./pages/PCBuilderPage";
import PremiumSoftwarePage from "./pages/PremiumSoftwarePage";
import ProfilePage from "./pages/ProfilePage";
import StorePage from "./pages/StorePage";

function App() {
  const { i18n, t } = useTranslation();

  useEffect(() => {
    const browserLang = navigator.language.startsWith("ar") ? "ar" : "en";
    i18n.changeLanguage(browserLang);
  }, [i18n]);

  return (
    <Router>
      <div style={{ padding: "10px", textAlign: "center" }}>
        <button onClick={() => i18n.changeLanguage("en")} style={{ margin: "0 10px", padding: "5px 15px" }}>
          English
        </button>
        <button onClick={() => i18n.changeLanguage("ar")} style={{ margin: "0 10px", padding: "5px 15px" }}>
          العربية
        </button>
      </div>

      <nav style={{ marginBottom: 20, textAlign: "center" }}>
        <Link to="/" style={{ margin: "0 10px" }}>{t("nav.home", "Home")}</Link>
        <Link to="/store" style={{ margin: "0 10px" }}>{t("nav.store", "Store")}</Link>
        <Link to="/pc-builder" style={{ margin: "0 10px" }}>{t("nav.pcBuilder", "PC Builder")}</Link>
        <Link to="/cart" style={{ margin: "0 10px" }}>{t("nav.cart", "Cart")}</Link>
        <Link to="/admin" style={{ margin: "0 10px" }}>{t("nav.admin", "Admin")}</Link>
        <Link to="/profile" style={{ margin: "0 10px" }}>{t("nav.profile", "Profile")}</Link>
        <Link to="/premium-software" style={{ margin: "0 10px" }}>{t("nav.premiumSoftware", "Premium Software")}</Link>
      </nav>

      <Routes>
        <Route path="/" element={<HomePage />} />
        <Route path="/store" element={<StorePage />} />
        <Route path="/pc-builder" element={<PCBuilderPage />} />
        <Route path="/cart" element={<div style={{ textAlign: "center" }}><h2>Cart Page</h2></div>} />
        <Route path="/admin" element={<AdminPage />} />
        <Route path="/profile" element={<ProfilePage />} />
        <Route path="/premium-software" element={<PremiumSoftwarePage />} />
      </Routes>
    </Router>
  );
}

export default App;
